import type { KeycloakLoginProps } from "../types";

const KeycloakLogin = ({ removeContainer, appname, onLogin }: KeycloakLoginProps) => (
  <div className={removeContainer ? "" : "sso__container"}>
    <div className="sso__alert">
      <p className="sso__alert--icon">
        <svg focusable="false" aria-hidden="true" viewBox="0 0 24 24" data-testid="SuccessOutlinedIcon" height={32} width={32}>
          <path d="M20,12A8,8 0 0,1 12,20A8,8 0 0,1 4,12A8,8 0 0,1 12,4C12.76,4 13.5,4.11 14.2, 4.31L15.77,2.74C14.61,2.26 13.34,2 12,2A10,10 0 0,0 2,12A10,10 0 0,0 12,22A10,10 0 0, 0 22,12M7.91,10.08L6.5,11.5L11,16L21,6L19.59,4.58L11,13.17L7.91,10.08Z"></path>
        </svg>
      </p>
      <p>
        <b>¡IMPORTANTE!</b> La contraseña es la misma que el usuario solo para la primera vez que ingrese con el SSO, posteriormente este te pedirá
        cambiarlo.
      </p>
    </div>

    <div className="ssoauth__container">
      <h3>{appname}</h3>
      <p>Continua con el SSO NAPCONTABLE e ingrese sus credenciales para continuar...</p>
      <button className="sso__button ssoauth__spacing sso__button--full" onClick={onLogin}>
        SSO NAPCONTABLE
      </button>
    </div>
  </div>
);

export default KeycloakLogin;
